class AccessLevel(Enum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class FileAccessControlSystem:
    """
    A file access control system that uses database transactions and locks
    to ensure atomic permission checks and file access operations.
    """

    def __init__(self, db_path: str = ":memory:", document_root: str = "./documents"):
        self.db_path = db_path
        self.document_root = document_root
        self._db_lock = threading.Lock()
        self._init_database()

    def _get_connection(self) -> sqlite3.Connection:
        """Create a new database connection with proper isolation level."""
        conn = sqlite3.connect(self.db_path, timeout=30)
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA foreign_keys=ON")
        conn.isolation_level = "DEFERRED"
        return conn

    def _init_database(self):
        """Initialize the database schema."""
        conn = self._get_connection()
        try:
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id TEXT PRIMARY KEY,
                    username TEXT UNIQUE NOT NULL,
                    is_active INTEGER NOT NULL DEFAULT 1,
                    created_at TEXT NOT NULL DEFAULT (datetime('now'))
                );

                CREATE TABLE IF NOT EXISTS files (
                    file_id TEXT PRIMARY KEY,
                    file_path TEXT UNIQUE NOT NULL,
                    owner_id TEXT NOT NULL,
                    is_deleted INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT (datetime('now')),
                    FOREIGN KEY (owner_id) REFERENCES users(user_id)
                );

                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id TEXT PRIMARY KEY,
                    user_id TEXT NOT NULL,
                    file_id TEXT NOT NULL,
                    access_level INTEGER NOT NULL DEFAULT 0,
                    granted_by TEXT NOT NULL,
                    granted_at TEXT NOT NULL DEFAULT (datetime('now')),
                    expires_at TEXT,
                    is_revoked INTEGER NOT NULL DEFAULT 0,
                    version INTEGER NOT NULL DEFAULT 1,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    FOREIGN KEY (granted_by) REFERENCES users(user_id),
                    UNIQUE(user_id, file_id)
                );

                CREATE TABLE IF NOT EXISTS access_log (
                    log_id TEXT PRIMARY KEY,
                    user_id TEXT NOT NULL,
                    file_id TEXT NOT NULL,
                    action TEXT NOT NULL,
                    result TEXT NOT NULL,
                    details TEXT,
                    timestamp TEXT NOT NULL DEFAULT (datetime('now')),
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id)
                );

                CREATE INDEX IF NOT EXISTS idx_permissions_user_file
                    ON permissions(user_id, file_id);
                CREATE INDEX IF NOT EXISTS idx_permissions_active
                    ON permissions(user_id, file_id, is_revoked, access_level);
                CREATE INDEX IF NOT EXISTS idx_access_log_user
                    ON access_log(user_id, timestamp);
            """)
            conn.commit()
        finally:
            conn.close()

    def add_user(self, username: str) -> str:
        """Add a new user to the system."""
        user_id = str(uuid.uuid4())
        conn = self._get_connection()
        try:
            conn.execute(
                "INSERT INTO users (user_id, username) VALUES (?, ?)",
                (user_id, username)
            )
            conn.commit()
            return user_id
        finally:
            conn.close()

    def register_file(self, file_path: str, owner_id: str) -> str:
        """Register a file in the system."""
        file_id = str(uuid.uuid4())
        conn = self._get_connection()
        try:
            conn.execute(
                "INSERT INTO files (file_id, file_path, owner_id) VALUES (?, ?, ?)",
                (file_id, file_path, owner_id)
            )
            # Owner automatically gets ADMIN access
            permission_id = str(uuid.uuid4())
            conn.execute(
                """INSERT INTO permissions 
                   (permission_id, user_id, file_id, access_level, granted_by)
                   VALUES (?, ?, ?, ?, ?)""",
                (permission_id, owner_id, file_id, AccessLevel.ADMIN.value, owner_id)
            )
            conn.commit()
            return file_id
        finally:
            conn.close()

    def grant_permission(
        self,
        granter_id: str,
        target_user_id: str,
        file_id: str,
        access_level: AccessLevel,
        expires_at: Optional[str] = None
    ) -> bool:
        """
        Grant permission to a user for a file.
        Uses a transaction to atomically verify the granter's permission
        and create/update the target's permission.
        """
        conn = self._get_connection()
        try:
            # Use IMMEDIATE transaction to acquire a write lock upfront,
            # preventing TOCTOU race conditions
            conn.execute("BEGIN IMMEDIATE")

            # Verify granter has ADMIN access (within the same transaction)
            cursor = conn.execute(
                """SELECT access_level FROM permissions
                   WHERE user_id = ? AND file_id = ? AND is_revoked = 0
                   AND (expires_at IS NULL OR expires_at > datetime('now'))""",
                (granter_id, file_id)
            )
            row = cursor.fetchone()
            if not row or row[0] < AccessLevel.ADMIN.value:
                conn.rollback()
                self._log_access(
                    conn, granter_id, file_id, "GRANT_PERMISSION", "DENIED",
                    f"Insufficient privileges to grant access to {target_user_id}"
                )
                return False

            # Atomically upsert the permission
            permission_id = str(uuid.uuid4())
            conn.execute(
                """INSERT INTO permissions 
                   (permission_id, user_id, file_id, access_level, granted_by, expires_at, is_revoked, version)
                   VALUES (?, ?, ?, ?, ?, ?, 0, 1)
                   ON CONFLICT(user_id, file_id) DO UPDATE SET
                       access_level = excluded.access_level,
                       granted_by = excluded.granted_by,
                       granted_at = datetime('now'),
                       expires_at = excluded.expires_at,
                       is_revoked = 0,
                       version = version + 1""",
                (permission_id, target_user_id, file_id, access_level.value,
                 granter_id, expires_at)
            )

            self._log_access(
                conn, granter_id, file_id, "GRANT_PERMISSION", "SUCCESS",
                f"Granted {access_level.name} to {target_user_id}"
            )
            conn.commit()
            return True
        except Exception as e:
            conn.rollback()
            raise
        finally:
            conn.close()

    def revoke_permission(
        self,
        revoker_id: str,
        target_user_id: str,
        file_id: str
    ) -> bool:
        """
        Revoke a user's permission to a file.
        Uses atomic transaction to verify and revoke in one operation.
        """
        conn = self._get_connection()
        try:
            conn.execute("BEGIN IMMEDIATE")

            # Verify revoker has ADMIN access
            cursor = conn.execute(
                """SELECT access_level FROM permissions
                   WHERE user_id = ? AND file_id = ? AND is_revoked = 0
                   AND (expires_at IS NULL OR expires_at > datetime('now'))""",
                (revoker_id, file_id)
            )
            row = cursor.fetchone()
            if not row or row[0] < AccessLevel.ADMIN.value:
                conn.rollback()
                return False

            # Atomically revoke the permission with optimistic concurrency
            result = conn.execute(
                """UPDATE permissions SET is_revoked = 1, version = version + 1
                   WHERE user_id = ? AND file_id = ? AND is_revoked = 0""",
                (target_user_id, file_id)
            )

            if result.rowcount == 0:
                conn.rollback()
                return False

            self._log_access(
                conn, revoker_id, file_id, "REVOKE_PERMISSION", "SUCCESS",
                f"Revoked access for {target_user_id}"
            )
            conn.commit()
            return True
        except Exception as e:
            conn.rollback()
            raise
        finally:
            conn.close()

    def read_file(self, user_id: str, file_id: str) -> Tuple[bool, Optional[str], str]:
        """
        Atomically check permission and read a file.
        
        Returns:
            Tuple of (success: bool, content: Optional[str], message: str)
        
        The permission check and the access log entry are performed within
        a single IMMEDIATE transaction to prevent TOCTOU race conditions
        where permissions could be revoked between the check and the read.
        """
        conn = self._get_connection()
        try:
            # BEGIN IMMEDIATE acquires a reserved lock immediately,
            # ensuring no other writer can modify permissions between
            # our check and our access log write.
            conn.execute("BEGIN IMMEDIATE")

            # Step 1: Verify user is active
            cursor = conn.execute(
                "SELECT is_active FROM users WHERE user_id = ?",
                (user_id,)
            )
            user_row = cursor.fetchone()
            if not user_row or not user_row[0]:
                self._log_access(
                    conn, user_id, file_id, "READ", "DENIED",
                    "User not found or inactive"
                )
                conn.commit()
                return (False, None, "User not found or inactive")

            # Step 2: Verify file exists and is not deleted
            cursor = conn.execute(
                "SELECT file_path, is_deleted FROM files WHERE file_id = ?",
                (file_id,)
            )
            file_row = cursor.fetchone()
            if not file_row:
                self._log_access(
                    conn, user_id, file_id, "READ", "DENIED",
                    "File not found"
                )
                conn.commit()
                return (False, None, "File not found")

            file_path, is_deleted = file_row
            if is_deleted:
                self._log_access(
                    conn, user_id, file_id, "READ", "DENIED",
                    "File has been deleted"
                )
                conn.commit()
                return (False, None, "File has been deleted")

            # Step 3: Check permission atomically within the same transaction
            cursor = conn.execute(
                """SELECT access_level, expires_at, version FROM permissions
                   WHERE user_id = ? AND file_id = ? AND is_revoked = 0
                   AND access_level >= ?
                   AND (expires_at IS NULL OR expires_at > datetime('now'))""",
                (user_id, file_id, AccessLevel.READ.value)
            )
            perm_row = cursor.fetchone()

            if not perm_row:
                self._log_access(
                    conn, user_id, file_id, "READ", "DENIED",
                    "Insufficient permissions or permission expired/revoked"
                )
                conn.commit()
                return (False, None, "Access denied: insufficient permissions")

            access_level, expires_at, perm_version = perm_row

            # Step 4: Log the successful access within the same transaction
            # This ensures the permission was valid at the exact moment of access
            self._log_access(
                conn, user_id, file_id, "READ", "SUCCESS",
                f"Access level: {access_level}, Permission version: {perm_version}"
            )

            # Commit the transaction (permission check + log are atomic)
            conn.commit()

            # Step 5: Now read the file from disk
            # The permission was validated and logged atomically.
            # Even if permission is revoked after commit, the access log
            # proves the permission was valid at time of access.
            full_path = self._resolve_file_path(file_path)
            if not full_path:
                return (False, None, "File not found on disk")

            try:
                with open(full_path, 'r', encoding='utf-8') as f:
                    content = f.read()
                return (True, content, "File read successfully")
            except FileNotFoundError:
                return (False, None, "File not found on disk")
            except PermissionError:
                return (False, None, "System permission error reading file")
            except Exception as e:
                return (False, None, f"Error reading file: {str(e)}")

        except Exception as e:
            conn.rollback()
            raise
        finally:
            conn.close()

    def _resolve_file_path(self, file_path: str) -> Optional[str]:
        """
        Safely resolve a file path, preventing directory traversal attacks.
        """
        # Normalize the path
        document_root = os.path.realpath(self.document_root)
        full_path = os.path.realpath(os.path.join(document_root, file_path))

        # Ensure the resolved path is within the document root
        if not full_path.startswith(document_root + os.sep) and full_path != document_root:
            return None

        if not os.path.isfile(full_path):
            return None

        return full_path

    def _log_access(
        self,
        conn: sqlite3.Connection,
        user_id: str,
        file_id: str,
        action: str,
        result: str,
        details: str = ""
    ):
        """Log an access attempt within an existing transaction."""
        log_id = str(uuid.uuid4())
        conn.execute(
            """INSERT INTO access_log (log_id, user_id, file_id, action, result, details)
               VALUES (?, ?, ?, ?, ?, ?)""",
            (log_id, user_id, file_id, action, result, details)
        )

    def get_access_log(
        self,
        file_id: Optional[str] = None,
        user_id: Optional[str] = None,
        limit: int = 100
    ) -> list:
        """Retrieve access log entries."""
        conn = self._get_connection()
        try:
            query = "SELECT * FROM access_log WHERE 1=1"
            params = []

            if file_id:
                query += " AND file_id = ?"
                params.append(file_id)
            if user_id:
                query += " AND user_id = ?"
                params.append(user_id)

            query += " ORDER BY timestamp DESC LIMIT ?"
            params.append(limit)

            cursor = conn.execute(query, params)
            columns = [desc[0] for desc in cursor.description]
            return [dict(zip(columns, row)) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_user_permissions(self, user_id: str) -> list:
        """Get all active permissions for a user."""
        conn = self._get_connection()
        try:
            cursor = conn.execute(
                """SELECT p.*, f.file_path FROM permissions p
                   JOIN files f ON p.file_id = f.file_id
                   WHERE p.user_id = ? AND p.is_revoked = 0
                   AND (p.expires_at IS NULL OR p.expires_at > datetime('now'))""",
                (user_id,)
            )
            columns = [desc[0] for desc in cursor.description]
            return [dict(zip(columns, row)) for row in cursor.fetchall()]
        finally:
            conn.close()


def demo():
    """Demonstrate the file access control system."""
    import tempfile
    import shutil

    # Create a temporary document root
    doc_root = tempfile.mkdtemp(prefix="docmgmt_")

    try:
        # Create some test files
        test_file_path = "reports/quarterly_report.txt"
        os.makedirs(os.path.join(doc_root, "reports"), exist_ok=True)
        with open(os.path.join(doc_root, test_file_path), 'w') as f:
            f.write("Q4 2024 Quarterly Report\n\nRevenue: $1.2M\nProfit: $300K\n")

        confidential_path = "confidential/salaries.txt"
        os.makedirs(os.path.join(doc_root, "confidential"), exist_ok=True)
        with open(os.path.join(doc_root, confidential_path), 'w') as f:
            f.write("Employee Salary Data - CONFIDENTIAL\n")

        # Initialize the system
        system = FileAccessControlSystem(document_root=doc_root)

        # Create users
        admin_id = system.add_user("admin")
        alice_id = system.add_user("alice")
        bob_id = system.add_user("bob")

        print("=== File Access Control System Demo ===\n")
        print(f"Admin ID: {admin_id}")
        print(f"Alice ID: {alice_id}")
        print(f"Bob ID:   {bob_id}\n")

        # Register files
        report_file_id = system.register_file(test_file_path, admin_id)
        confidential_file_id = system.register_file(confidential_path, admin_id)

        print(f"Report File ID:       {report_file_id}")
        print(f"Confidential File ID: {confidential_file_id}\n")

        # Test 1: Admin reads their own file
        print("--- Test 1: Admin reads report ---")
        success, content, msg = system.read_file(admin_id, report_file_id)
        print(f"Success: {success}, Message: {msg}")
        if content:
            print(f"Content: {content[:50]}...\n")

        # Test 2: Alice tries to read without permission
        print("--- Test 2: Alice tries to read report (no permission) ---")
        success, content, msg = system.read_file(alice_id, report_file_id)
        print(f"Success: {success}, Message: {msg}\n")

        # Test 3: Grant Alice READ access, then she reads
        print("--- Test 3: Grant Alice READ access, then read ---")
        granted = system.grant_permission(
            admin_id, alice_id, report_file_id, AccessLevel.READ
        )
        print(f"Permission granted: {granted}")
        success, content, msg = system.read_file(alice_id, report_file_id)
        print(f"Success: {success}, Message: {msg}")
        if content:
            print(f"Content: {content[:50]}...\n")

        # Test 4: Bob tries to grant himself access (should fail)
        print("--- Test 4: Bob tries to grant himself access ---")
        granted = system.grant_permission(
            bob_id, bob_id, report_file_id, AccessLevel.READ
        )
        print(f"Permission granted: {granted}\n")

        # Test 5: Revoke Alice's access, then she tries to read
        print("--- Test 5: Revoke Alice's access, then try to read ---")
        revoked = system.revoke_permission(admin_id, alice_id, report_file_id)
        print(f"Permission revoked: {revoked}")
        success, content, msg = system.read_file(alice_id, report_file_id)
        print(f"Success: {success}, Message: {msg}\n")

        # Test 6: Concurrent access simulation
        print("--- Test 6: Concurrent access simulation ---")
        # Re-grant Alice access for concurrent test
        system.grant_permission(
            admin_id, alice_id, report_file_id, AccessLevel.READ
        )

        results = []
        errors = []

        def concurrent_read(uid, fid, thread_name):
            try:
                s, c, m = system.read_file(uid, fid)
                results.append((thread_name, s, m))
            except Exception as e:
                errors.append((thread_name, str(e)))

        def concurrent_revoke(revoker, target, fid, thread_name):
            try:
                r = system.revoke_permission(revoker, target, fid)
                results.append((thread_name, r, "revoke attempted"))
            except Exception as e:
                errors.append((thread_name, str(e)))

        threads = []
        for i in range(5):
            t = threading.Thread(
                target=concurrent_read,
                args=(alice_id, report_file_id, f"reader-{i}")
            )
            threads.append(t)

        # Add a revoker thread that will race with readers
        t_revoke = threading.Thread(
            target=concurrent_revoke,
            args=(admin_id, alice_id, report_file_id, "revoker")
        )
        threads.append(t_revoke)

        for t in threads:
            t.start()
        for t in threads:
            t.join()

        for name, success_val, msg in sorted(results):
            print(f"  {name}: success={success_val}, msg={msg}")
        for name, err in errors:
            print(f"  {name}: ERROR={err}")

        print(f"\n--- Access Log (last 15 entries) ---")
        logs = system.get_access_log(limit=15)
        for log in logs:
            print(f"  [{log['timestamp']}] {log['action']}: {log['result']} - {log['details']}")

        # Test 7: Directory traversal prevention
        print("\n--- Test 7: Path traversal prevention ---")
        try:
            traversal_file_id = system.register_file("../../etc/passwd", admin_id)
            success, content, msg = system.read_file(admin_id, traversal_file_id)
            print(f"Traversal attempt: Success={success}, Message={msg}")
        except Exception as e:
            print(f"Traversal attempt blocked: {e}")

    finally:
        shutil.rmtree(doc_root, ignore_errors=True)


